#include <iostream>
using namespace std;

int main() {
    int numbers[] = {10, 20, 30, 40, 50, 60};

    int totalBytes = sizeof(numbers);
    int elementBytes = sizeof(numbers[0]);
    int elementCount = sizeof(numbers) / sizeof(numbers[0]);

    cout << "Total bytes: " << totalBytes << endl;
    cout << "Bytes per element: " << elementBytes << endl;
    cout << "Number of elements: " << elementCount << endl;

    // Safe loop
    for (int i = 0; i < elementCount; i++) {
        cout << numbers[i] << " ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int arr[] = {5, 10, 15, 20};
    int* ptr = arr;  // points to arr[0]

    cout << "arr[0] = " << arr[0] << ", *ptr = " << *ptr << endl;
    cout << "arr[1] = " << arr[1] << ", *(ptr+1) = " << *(ptr+1) << endl;

    // Array indexing is pointer arithmetic
    cout << "2[arr] = " << 2[arr] << endl;  // same as arr[2]

    // Important: sizeof(arr) gives array size, sizeof(ptr) gives pointer size
    cout << "sizeof(arr): " << sizeof(arr) << endl;
    cout << "sizeof(ptr): " << sizeof(ptr) << endl;

    return 0;
}

#include <iostream>
using namespace std;

// Array parameter decays to pointer
void printArray(int arr[], int size) {
    for (int i = 0; i < size; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
}

void doubleElements(int* arr, int size) {  // int* is same as int[]
    for (int i = 0; i < size; i++) {
        arr[i] *= 2;
    }
}

// Return size via reference
void fillArray(int arr[], int size, int& filledCount) {
    for (int i = 0; i < size && i < 5; i++) {
        arr[i] = i * 10;
        filledCount++;
    }
}

int main() {
    int data[] = {1, 2, 3, 4, 5};
    int size = sizeof(data)/sizeof(data[0]);

    printArray(data, size);
    doubleElements(data, size);
    printArray(data, size);  // doubled

    int arr2[10];
    int count = 0;
    fillArray(arr2, 10, count);
    cout << "Filled " << count << " elements" << endl;

    return 0;
}

