#include <iostream>
using namespace std;

int main() {
    int n;
    cout << "Enter array size: ";
    cin >> n;

    // Dynamic allocation
    int* arr = new int[n];

    // Initialize
    for (int i = 0; i < n; i++) {
        arr[i] = i * 10;
    }

    // Use
    for (int i = 0; i < n; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    // Free memory
    delete[] arr;
    arr = nullptr;

    // Better: use std::vector for dynamic arrays (modern C++)
    // #include <vector>
    // vector<int> vec(n);

    return 0;
}

#include <iostream>
using namespace std;

class Point {
public:
    int x, y;
    Point(int a = 0, int b = 0) : x(a), y(b) {
        cout << "Point(" << x << "," << y << ") created" << endl;
    }
    void display() { cout << "(" << x << "," << y << ")" << endl; }
};

int main() {
    Point points[3] = {{1,2}, {3,4}, {5,6}};
    for (int i = 0; i < 3; i++) {
        points[i].display();
    }

    // Dynamic array of objects
    Point* pArray = new Point[2]{{10,20}, {30,40}};
    pArray[0].display();
    delete[] pArray;

    return 0;
}

#include <iostream>
using namespace std;

void badFunction(int arr[]) {
    // sizeof(arr) is pointer size, NOT array size!
    cout << "Inside function, sizeof(arr) = " << sizeof(arr) << " bytes" << endl;
}

int main() {
    int arr[10];
    cout << "In main, sizeof(arr) = " << sizeof(arr) << " bytes" << endl;
    badFunction(arr);

